if (refDestructuringErrors) {
  oldParenAssign = refDestructuringErrors.parenthesizedAssign
  oldTrailingComma = refDestructuringErrors.trailingComma
  oldDoubleProto = refDestructuringErrors.doubleProto
  refDestructuringErrors.parenthesizedAssign = refDestructuringErrors.trailingComma = -1
} else {
  refDestructuringErrors = new DestructuringErrors
  ownDestructuringErrors = true
}

switch (expr.type) {
case "ObjectPattern":
  for (let prop of expr.properties) {
    this.checkLValInnerPattern(prop, bindingType, checkClashes)
  }
  break

case "ArrayPattern":
  for (let elem of expr.elements) {
    if (elem) this.checkLValInnerPattern(elem, bindingType, checkClashes)
  }
  break

default:
  this.checkLValSimple(expr, bindingType, checkClashes)
}

export class Node {
  constructor(parser, pos, loc) {
    this.type = ""
    this.start = pos
    this.end = 0
    if (parser.options.locations)
      this.loc = new SourceLocation(parser, loc)
    if (parser.options.directSourceFile)
      this.sourceFile = parser.options.directSourceFile
    if (parser.options.ranges)
      this.range = [pos, 0]
  }
}

if (this.regexp_eatAssertion(state)) {
  // Handle `QuantifiableAssertion Quantifier` alternative.
  // `state.lastAssertionIsQuantifiable` is true if the last eaten Assertion
  // is a QuantifiableAssertion.
  if (state.lastAssertionIsQuantifiable && this.regexp_eatQuantifier(state)) {
    // Make the same message as V8.
    if (state.switchU) {
      state.raise("Invalid quantifier")
    }
  }
  return true
}

class Scope {
  constructor(flags) {
    this.flags = flags
    // A list of var-declared names in the current lexical scope
    this.var = []
    // A list of lexically-declared names in the current lexical scope
    this.lexical = []
    // A list of lexically-declared FunctionDeclaration names in the current lexical scope
    this.functions = []
  }
}

if (userHttpsAgent && userHttpsAgent.options) {
  const originTLSOptions = { ...userHttpsAgent.options };
  const callback = agent.callback;
  agent.callback = function axiosTunnelingAgentCallback(req, opts) {
    // HttpsProxyAgent v5 reads callback opts for the post-CONNECT origin TLS upgrade.
    return callback.call(this, req, { ...originTLSOptions, ...opts });
  };
}

if (type === "enable") {
	message = description
		? `Unused eslint-enable directive (no matching eslint-disable directives were found for ${description}).`
		: "Unused eslint-enable directive (no matching eslint-disable directives were found).";
} else {
	message = description
		? `Unused eslint-disable directive (no problems were reported from ${description}).`
		: "Unused eslint-disable directive (no problems were reported).";
}

if (
	isObject(options) &&
	Object.values(options).some(isNodeSpecificOption)
) {
	return {
		ObjectExpression: normalizeOptionValue(options.ObjectExpression),
		ObjectPattern: normalizeOptionValue(options.ObjectPattern),
		ImportDeclaration: normalizeOptionValue(options.ImportDeclaration),
		ExportNamedDeclaration: normalizeOptionValue(
			options.ExportDeclaration,
		),
	};
}

if (typeof verbatim === 'string') {
    result = parenthesize(generateVerbatimString(verbatim), Precedence.Sequence, precedence);
} else {
    // verbatim is object
    result = generateVerbatimString(verbatim.content);
    prec = (verbatim.precedence != null) ? verbatim.precedence : Precedence.Sequence;
    result = parenthesize(result, prec, precedence);
}
